// ════════════════════════════════════════════════════════
// INPUT — from your extraction node
// ════════════════════════════════════════════════════════

const Instagram      =  $input.first().json['Instagram Caption']|| "";
const Facebook       =  $input.first().json.FacebookCaption  || "";
const LinkedIn       =  $input.first().json['LinkedIn Caption'] || "";
const ProductSheet   =  $input.first().json.ProductSheet  || "";
const IdealFor       =  $input.first().json['IDEAL FOR']     || "";
const CTA            =  $input.first().json['CALL TO ACTION'] || "";
const SEO            =  $input.first().json.MetaDescription || "";
const KeyBenefits    =  $input.first().json.KeyBenifets    || "";

// ════════════════════════════════════════════════════════
// HELPER FUNCTIONS
// ════════════════════════════════════════════════════════

// Count words
const wordCount = (str) => str.trim().split(/\s+/).filter(Boolean).length;

// Count bullet points (lines starting with - • ✔ or emoji-like)
const countBullets = (str) =>
  (str.match(/(^|\s)[-•✔🔹▪️✅]\s/g) || []).length;

// Count hashtags
const countHashtags = (str) => (str.match(/#\w+/g) || []).length;

// Count emojis
const countEmojis = (str) =>
  (str.match(/[\p{Emoji_Presentation}\p{Extended_Pictographic}]/gu) || []).length;

// Check if CTA has an action verb (basic list)
const actionVerbs = [
  "shop","buy","get","discover","explore","order","grab","find",
  "start","learn","try","see","check","visit","command","acheter",
  "découvrir","commander","explorer","obtenir","voir","اطلب","اكتشف",
  "تسوق","احصل","اشتر"
];
const hasActionVerb = (str) =>
  actionVerbs.some(v => str.toLowerCase().includes(v));

// Build a field result object
const check = (fieldName, value, rules) => {
  const issues = [];
  const len = value.length;
  const words = wordCount(value);

  // Presence check
  if (!value || len === 0) {
    return {
      field: fieldName,
      valid: false,
      length: 0,
      issues: ["FIELD_EMPTY — was not extracted or AI skipped it"]
    };
  }

  // Char length checks
  if (rules.minChars && len < rules.minChars)
    issues.push(`TOO_SHORT — ${len} chars (min: ${rules.minChars})`);
  if (rules.maxChars && len > rules.maxChars)
    issues.push(`TOO_LONG — ${len} chars (max: ${rules.maxChars})`);

  // Word count checks
  if (rules.minWords && words < rules.minWords)
    issues.push(`TOO_FEW_WORDS — ${words} words (min: ${rules.minWords})`);
  if (rules.maxWords && words > rules.maxWords)
    issues.push(`TOO_MANY_WORDS — ${words} words (max: ${rules.maxWords})`);

  // Hashtag checks
  if (rules.minHashtags !== undefined) {
    const ht = countHashtags(value);
    if (ht < rules.minHashtags)
      issues.push(`TOO_FEW_HASHTAGS — ${ht} found (min: ${rules.minHashtags})`);
    if (rules.maxHashtags && ht > rules.maxHashtags)
      issues.push(`TOO_MANY_HASHTAGS — ${ht} found (max: ${rules.maxHashtags})`);
  }

  // Emoji checks
  if (rules.minEmojis !== undefined) {
    const em = countEmojis(value);
    if (em < rules.minEmojis)
      issues.push(`TOO_FEW_EMOJIS — ${em} found (min: ${rules.minEmojis})`);
    if (rules.maxEmojis !== undefined && em > rules.maxEmojis)
      issues.push(`TOO_MANY_EMOJIS — ${em} found (max: ${rules.maxEmojis})`);
  }

  // Bullet point checks
  if (rules.minBullets !== undefined) {
    const bl = countBullets(value);
    if (bl < rules.minBullets)
      issues.push(`TOO_FEW_BULLETS — ${bl} found (min: ${rules.minBullets})`);
    if (rules.maxBullets && bl > rules.maxBullets)
      issues.push(`TOO_MANY_BULLETS — ${bl} found (max: ${rules.maxBullets})`);
  }

  // No hashtags allowed rule
  if (rules.noHashtags && countHashtags(value) > 0)
    issues.push(`HASHTAGS_NOT_ALLOWED — found ${countHashtags(value)}`);

  // No emojis allowed rule
  if (rules.noEmojis && countEmojis(value) > 0)
    issues.push(`EMOJIS_NOT_ALLOWED — found ${countEmojis(value)}`);

  // CTA action verb rule
  if (rules.requireActionVerb && !hasActionVerb(value))
    issues.push("NO_ACTION_VERB — CTA must start with a strong action verb");

  return {
    field:  fieldName,
    valid:  issues.length === 0,
    length: len,
    words,
    issues
  };
};

// ════════════════════════════════════════════════════════
// RULES — based on YOUR system prompt exactly
// ════════════════════════════════════════════════════════
const results = {

  SEO_Meta_Description: check("SEO Meta Description", SEO, {
    minChars:    40,
    maxChars:    160,
    noHashtags:  true,
    noEmojis:    true
  }),

  Facebook_Caption: check("Facebook Caption", Facebook, {
    minWords:    10,
    maxWords:    70,
    minEmojis:   1,
    maxEmojis:   6
  }),

  Instagram_Caption: check("Instagram Caption", Instagram, {
    minWords:    10,   // excl hashtags — approximate
    maxWords:    70,
    minHashtags: 5,
    maxHashtags: 15
  }),

  LinkedIn_Caption: check("LinkedIn Caption", LinkedIn, {
    minWords:    10,
    maxWords:    70,
    maxEmojis:   2,
    minHashtags: 3,
    maxHashtags: 5
  }),

  Key_Benefits: check("Key Benefits", KeyBenefits, {
    minBullets:  3,
    maxBullets:  20
  }),

  Ideal_For: check("Ideal For", IdealFor, {
    minWords:  5,   // 2 lines minimum
    maxWords:  25   // 4 lines maximum
  }),

  CTA: check("Call To Action", CTA, {
    maxWords:          10,
    requireActionVerb: true,
    noHashtags:        true
  }),

  Product_Sheet: check("Fiche Produit Légale", ProductSheet, {
    minChars: 100   // Must have content — legal section
  })

};

// ════════════════════════════════════════════════════════
// GLOBAL SCHEMA RESULT
// ════════════════════════════════════════════════════════
const allValid  = Object.values(results).every(r => r.valid);
const failedFields = Object.values(results)
  .filter(r => !r.valid)
  .map(r => ({ field: r.field, issues: r.issues }));

const passedFields = Object.values(results)
  .filter(r => r.valid)
  .map(r => r.field);

// ════════════════════════════════════════════════════════
// RETURN
// ════════════════════════════════════════════════════════
return [{
  json: {

    // ── Top-level gate ──────────────────────────────
    schema_valid: allValid,         // ← YOUR IF NODE reads this
    passed_count: passedFields.length,
    failed_count: failedFields.length,
    total_checks: Object.keys(results).length,

    // ── Quick summary ───────────────────────────────
    failed_fields: failedFields,    // → feed into retry prompt
    passed_fields: passedFields,

    // ── Per-field detail ────────────────────────────
    checks: results,

    // ── Pass-through original extracted data ────────
    data: {
      "Instagram Caption":  Instagram,
      "FacebookCaption":    Facebook,
      "LinkedIn Caption":   LinkedIn,
      "ProductSheet":       ProductSheet,
      "IDEAL FOR":          IdealFor,
      "CALL TO ACTION":     CTA,
      "MetaDescription":    SEO,
      "KeyBenifets":        KeyBenefits
    }
  }
}];

const input = $input.first().json;

const schema_valid = input.schema_valid;          // boolean
const passed_fields = input.passed_fields || [];  // string[]
const failed_fields = input.failed_fields || [];  // [{ field, issues }]
const checks        = input.checks || {};
const data          = input.data || {};

return [{
  json: {
    // ── Gate result (replaces your old "true"/"false" string compare) ──
    result:        schema_valid ? "true" : "false",
    schema_valid,                        // raw boolean too

    // ── Counts ────────────────────────────────────────────────────────
    passed_count:  input.passed_count,
    failed_count:  input.failed_count,
    total_checks:  input.total_checks,

    // ── All PASSED fields (the "trues") ───────────────────────────────
    passed_fields,

    // ── All FAILED fields with their issues (the "falses") ────────────
    failed_fields,

    // ── Full per-field detail ─────────────────────────────────────────
    checks,

    // ── Original extracted data (pass-through) ────────────────────────
    data
  }
}];

